// LESSON: Reference Page 1 - Array och loopar.
// You will learn: Use array indexes, bounds checks, enhanced for, and Arrays helpers.
class Prog2Reference435 {
  // EXEMPEL 1: En array har fast langd och index fran 0.
  static int sumWithIndex() {
    int[] scores = { 3, 5, 8 };
    int total = 0;
    for (int i = 0; i < scores.length; i++) { total += scores[i]; }
    return total;
  }
  // EXEMPEL 2: Enhanced for passar nar index inte behovs.
  static int maxValue(int[] values) {
    int max = values[0];
    for (int value : values) { if (value > max) { max = value; } }
    return max;
  }
  // EXEMPEL 3: Arrays-klassen har hjalpare for kopiering och sortering.
  static int[] sortedCopy(int[] values) {
    int[] copy = java.util.Arrays.copyOf(values, values.length);
    java.util.Arrays.sort(copy);
    return copy;
  }
}
